+    function fetchAsArrayBuffer(url) {
+        // XHR handles binary responses more reliably than fetch on iOS Safari,
+        // where Brotli-compressed arrayBuffer() responses can arrive corrupted.
+        return new Promise((resolve, reject) => {
+            const xhr = new XMLHttpRequest();
+            xhr.open("GET", url, true);
+            xhr.responseType = "arraybuffer";
+            xhr.onload = () => {
+                if (xhr.status >= 200 && xhr.status < 300) resolve(xhr.response);
+                else reject(new Error(`HTTP ${xhr.status} fetching ${url}`));
+            };
+            xhr.onerror = () => reject(new Error(`Network error fetching ${url}`));
+            xhr.send();
+        });
+    }
+
